import { useState } from 'react';
import api from '../../services/api';
import toast from 'react-hot-toast';

export default function ProductoForm({ producto, onClose }) {
  const [formData, setFormData] = useState({
    codigo: producto?.codigo || '',
    nombre: producto?.nombre || '',
    descripcion: producto?.descripcion || '',
    precio_compra: producto?.precio_compra || '',
    precio_venta: producto?.precio_venta || '',
    stock_actual: producto?.stock_actual || 0,
    stock_minimo: producto?.stock_minimo || 0,
    unidad_medida: producto?.unidad_medida || 'unidad'
  });
  const [loading, setLoading] = useState(false);

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      if (producto) {
        await api.put(`/productos/${producto.id}`, formData);
        toast.success('Producto actualizado');
      } else {
        await api.post('/productos', formData);
        toast.success('Producto creado');
      }
      onClose();
    } catch (error) {
      toast.error(error.response?.data?.error || 'Error al guardar');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 flex justify-center items-center z-50">
      <div className="bg-white p-6 rounded shadow-lg w-full max-w-md">
        <h2 className="text-xl font-bold mb-4">{producto ? 'Editar Producto' : 'Nuevo Producto'}</h2>
        <form onSubmit={handleSubmit}>
          <div className="mb-3">
            <label className="block text-sm">Código *</label>
            <input name="codigo" value={formData.codigo} onChange={handleChange} required className="w-full border p-2 rounded" />
          </div>
          <div className="mb-3">
            <label className="block text-sm">Nombre *</label>
            <input name="nombre" value={formData.nombre} onChange={handleChange} required className="w-full border p-2 rounded" />
          </div>
          <div className="mb-3">
            <label className="block text-sm">Descripción</label>
            <textarea name="descripcion" value={formData.descripcion} onChange={handleChange} className="w-full border p-2 rounded" rows="2"></textarea>
          </div>
          <div className="grid grid-cols-2 gap-2">
            <div className="mb-3">
              <label className="block text-sm">Precio compra</label>
              <input type="number" step="0.01" name="precio_compra" value={formData.precio_compra} onChange={handleChange} required className="w-full border p-2 rounded" />
            </div>
            <div className="mb-3">
              <label className="block text-sm">Precio venta</label>
              <input type="number" step="0.01" name="precio_venta" value={formData.precio_venta} onChange={handleChange} required className="w-full border p-2 rounded" />
            </div>
          </div>
          <div className="grid grid-cols-2 gap-2">
            <div className="mb-3">
              <label className="block text-sm">Stock actual</label>
              <input type="number" name="stock_actual" value={formData.stock_actual} onChange={handleChange} className="w-full border p-2 rounded" />
            </div>
            <div className="mb-3">
              <label className="block text-sm">Stock mínimo</label>
              <input type="number" name="stock_minimo" value={formData.stock_minimo} onChange={handleChange} className="w-full border p-2 rounded" />
            </div>
          </div>
          <div className="flex justify-end space-x-2">
            <button type="button" onClick={onClose} className="bg-gray-400 text-white px-4 py-2 rounded">Cancelar</button>
            <button type="submit" disabled={loading} className="bg-blue-600 text-white px-4 py-2 rounded">
              {loading ? 'Guardando...' : 'Guardar'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}
